export default function LibraryApp() {
  const [books, setBooks] = useState([]);
  const [readers, setReaders] = useState([]);
  const [loans, setLoans] = useState([]);
  const [session, setSession] = useState(null);
  const [page, setPage] = useState("home");
  const [toast, setToast] = useState(null);
  const [loading, setLoading] = useState(true);
  const [librarianPin, setLibrarianPinState] = useState("999999");
  const savingRef = useRef(false);

  useEffect(() => {
    const fetchAll = async () => {
      if (savingRef.current) return;
      const [b, r, l] = await Promise.all([
        loadBooks(),
        loadData(STORAGE_KEYS.READERS),
        loadData(STORAGE_KEYS.LOANS),
      ]);
      if (savingRef.current) return;
      if (b) setBooks(b);
      if (r) setReaders(r);
      if (l) setLoans(l);
    };

    const init = async () => {
      await fetchAll();
      const p = await loadData("lib_librarian_pin");
      if (p) setLibrarianPinState(p);
      setLoading(false);
    };
    init();

    // רענון אוטומטי כל 60 שניות
    const interval = setInterval(fetchAll, 60000);
    return () => clearInterval(interval);
  }, []);

  const setLibrarianPin = (pin) => {
    setLibrarianPinState(pin);
    saveData("lib_librarian_pin", pin);
  };

  const showToast = useCallback((msg) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3000);
  }, []);

  const persist = useCallback(async (b, r, l, prevBooks) => {
    savingRef.current = true;
    try {
      const newIds = new Set(b.map(book => book.id));
      const oldIds = new Set((prevBooks || []).map(book => book.id));
      await Promise.all(b.map(book => saveBook(book)));
      await Promise.all([...oldIds].filter(id => !newIds.has(id)).map(id => deleteBook(id)));
      await Promise.all([
        saveData(STORAGE_KEYS.READERS, r),
        saveData(STORAGE_KEYS.LOANS, l),
      ]);
    } finally {
      savingRef.current = false;
    }
  }, []);

  const updateAll = (b, r, l) => {
    const prevBooks = books;
    setBooks(b); setReaders(r); setLoans(l);
    persist(b, r, l, prevBooks);
  };

  const logout = () => { setSession(null); setPage("home"); };

  if (loading) return (
    <div style={{ display:"flex",alignItems:"center",justifyContent:"center",height:"100vh",fontFamily:"'Alef',Arial,sans-serif", fontWeight:700,color:"#8b3a1a",fontSize:"1.5rem" }}>
      <style>{FONTS}</style>
      טוען ספרייה...
    </div>
  );

  return (
    <div className="app-wrap" dir="rtl">
      <style>{FONTS}</style>
      <Header session={session} onLogout={logout} />
      {!session && (
        <AuthScreen onLogin={setSession} readers={readers} books={books} loans={loans} updateAll={updateAll} showToast={showToast} librarianPin={librarianPin} />
      )}
      {session?.role === "librarian" && (
        <LibrarianDashboard
          books={books} readers={readers} loans={loans}
          updateAll={updateAll} page={page} setPage={setPage}
          showToast={showToast} librarianPin={librarianPin} setLibrarianPin={setLibrarianPin}
        />
      )}
      {session?.role === "reader" && (
        <ReaderDashboard
          books={books} readers={readers} loans={loans}
          updateAll={updateAll} readerId={session.readerId}
          page={page} setPage={setPage} showToast={showToast}
        />
      )}
      {toast && <div className="toast">{toast}</div>}
    </div>
  );
}

// ── HEADER ──
function Header({ session, onLogout }) {
  return (
    <header className="site-header">
      <div style={{display:"flex", alignItems:"center", gap:"0.6rem"}}>
        <img src="data:image/jpeg;base64," alt="לוגו" style={{height:"38px", width:"38px", objectFit:"contain", filter:"invert(1) brightness(2)"}} />
        <div>
          <span className="logo-text">ספריית נס הרים</span>
        </div>
      </div>
      {session && (
        <button className="btn btn-secondary btn-sm" onClick={onLogout}>יציאה ↩</button>
      )}
    </header>
  );
}

// ── AUTH SCREEN ──
function AuthScreen({ onLogin, readers, books, loans, updateAll, showToast, librarianPin }) {
  const [mode, setMode] = useState(null); // null | 'librarian' | 'reader'
  const [readerSubMode, setReaderSubMode] = useState(null); // null | 'login' | 'register'
  const [libPin, setLibPin] = useState("");
  const [readerPhone, setReaderPhone] = useState("");
  const [readerPin, setReaderPin] = useState("");
  const [err, setErr] = useState("");

  // Registration fields
  const [regPhone, setRegPhone] = useState("");
  const [regFirst, setRegFirst] = useState("");
  const [regLast, setRegLast] = useState("");
  const [regPin, setRegPin] = useState("");
  const [regPinConfirm, setRegPinConfirm] = useState("");

  const isAdmin = window.location.pathname === "/admin";
  useEffect(() => {
    if (isAdmin) setMode("librarian");
  }, []);

  const loginLibrarian = () => {
    if (libPin === librarianPin) {
      onLogin({ role: "librarian" });
    } else {
      setErr("קוד שגוי. נסי שנית.");
    }
  };

  const loginReader = () => {
    const reader = readers.find(r => r.phone === readerPhone && r.pin === readerPin);
    if (reader) {
      onLogin({ role: "reader", readerId: reader.id });
    } else {
      setErr("פרטים שגויים. נסי שנית.");
    }
  };

  const registerReader = () => {
    setErr("");
    if (!regFirst.trim() || !regLast.trim()) return setErr("יש להזין שם פרטי ושם משפחה.");
    if (!regPhone.trim()) return setErr("יש להזין מספר טלפון.");
    if (readers.find(r => r.phone === regPhone)) return setErr("מספר טלפון זה כבר רשום במערכת.");
    if (regPin.length !== 4 || !/^\d{4}$/.test(regPin)) return setErr("קוד אישי חייב להיות 4 ספרות.");
    if (regPin !== regPinConfirm) return setErr("הקודים האישיים אינם תואמים.");
    const newReader = {
      id: "r" + Date.now(),
      firstName: regFirst.trim(),
      lastName: regLast.trim(),
      phone: regPhone.trim(),
      pin: regPin,
    };
    const newReaders = [...readers, newReader];
    updateAll(books, newReaders, loans);
    showToast("✓ נרשמת בהצלחה! ברוך הבא לספריית נס הרים 🎉");
    onLogin({ role: "reader", readerId: newReader.id });
  };

  if (!mode) return (
    <div className="auth-screen">
      <div className="ornament">✦ ✦ ✦</div>
      <img src="data:image/jpeg;base64," alt="לוגו ספריית נס הרים" style={{width:"140px", height:"140px", objectFit:"contain", marginBottom:"0.5rem"}} />
      <h1 className="auth-title">ברוכים הבאים<br />לספריית נס הרים</h1>
      <p className="auth-subtitle">בחר/י את סוג הכניסה</p>
      <div className="role-cards">
        <div className="role-card" onClick={() => setMode("reader")}>
          <div className="icon">📖</div>
          <h3>מנוי / קורא</h3>
          <p>הספרים שלי, תאריכי החזרה</p>
        </div>
      </div>
      <div className="ornament">· · ·</div>
    </div>
  );

  return (
    <div className="auth-screen">
      <div className="login-form">
        {mode === "librarian" ? (
          <>
            <h2>👩‍💼 כניסת ספרנית</h2>
            <div className="form-group">
              <label>קוד כניסה</label>
              <input type="password" value={libPin} onChange={e => { setLibPin(e.target.value); setErr(""); }}
                placeholder="••••••" maxLength={6} onKeyDown={e => e.key === "Enter" && loginLibrarian()} />
            </div>
            {err && <p style={{ color:"var(--rust)", marginBottom:"0.8rem", fontSize:"0.9rem" }}>{err}</p>}
            <div style={{ display:"flex", gap:"0.7rem" }}>
              <button className="btn btn-primary" onClick={loginLibrarian}>כניסה</button>
              <button className="btn btn-secondary" onClick={() => { setMode(null); setErr(""); }}>חזרה</button>
            </div>
          </>
        ) : readerSubMode === null ? (
          <>
            <h2>📖 כניסת מנוי</h2>
            <div style={{ display:"flex", flexDirection:"column", gap:"0.8rem", marginTop:"0.5rem" }}>
              <button className="btn btn-primary btn-full" onClick={() => { setReaderSubMode("login"); setErr(""); }}>
                🔑 כניסה — משתמש קיים
              </button>
              <button className="btn btn-secondary btn-full" onClick={() => { setReaderSubMode("register"); setErr(""); }}>
                ✨ הרשמה — משתמש חדש
              </button>
            </div>
            <div style={{ marginTop:"1rem" }}>
              <button className="btn-link" onClick={() => { setMode(null); setErr(""); }}>← חזרה</button>
            </div>
          </>
        ) : readerSubMode === "login" ? (
          <>
            <h2>🔑 כניסת מנוי קיים</h2>
            <div className="form-group">
              <label>מספר טלפון</label>
              <input value={readerPhone} onChange={e => { setReaderPhone(formatPhone(e.target.value)); setErr(""); }} placeholder="052-1234567" />
            </div>
            <div className="form-group">
              <label>קוד אישי (4 ספרות)</label>
              <input type="password" value={readerPin} onChange={e => { setReaderPin(e.target.value); setErr(""); }}
                placeholder="••••" maxLength={4} onKeyDown={e => e.key === "Enter" && loginReader()} />
            </div>
            {err && <p style={{ color:"var(--rust)", marginBottom:"0.8rem", fontSize:"0.9rem" }}>{err}</p>}
            <div style={{ display:"flex", gap:"0.7rem" }}>
              <button className="btn btn-primary" onClick={loginReader}>כניסה</button>
              <button className="btn btn-secondary" onClick={() => { setReaderSubMode(null); setErr(""); }}>חזרה</button>
            </div>
          </>
        ) : (
          <>
            <h2>✨ הרשמה כמנוי חדש</h2>
            <div className="form-group">
              <label>שם פרטי *</label>
              <input value={regFirst} onChange={e => { setRegFirst(e.target.value); setErr(""); }} placeholder="שם פרטי" />
            </div>
            <div className="form-group">
              <label>שם משפחה *</label>
              <input value={regLast} onChange={e => { setRegLast(e.target.value); setErr(""); }} placeholder="שם משפחה" />
            </div>
            <div className="form-group">
              <label>מספר טלפון *</label>
              <input value={regPhone} onChange={e => { setRegPhone(formatPhone(e.target.value)); setErr(""); }} placeholder="052-1234567" />
            </div>
            <div className="form-group">
              <label>קוד אישי (4 ספרות) *</label>
              <input type="password" value={regPin} onChange={e => { setRegPin(e.target.value); setErr(""); }}
                placeholder="••••" maxLength={4} />
            </div>
            <div className="form-group">
              <label>אימות קוד אישי *</label>
              <input type="password" value={regPinConfirm} onChange={e => { setRegPinConfirm(e.target.value); setErr(""); }}
                placeholder="••••" maxLength={4} onKeyDown={e => e.key === "Enter" && registerReader()} />
            </div>
            {err && <p style={{ color:"var(--rust)", marginBottom:"0.8rem", fontSize:"0.9rem" }}>{err}</p>}
            <div style={{ display:"flex", gap:"0.7rem" }}>
              <button className="btn btn-primary" onClick={registerReader}>הרשמה</button>
              <button className="btn btn-secondary" onClick={() => { setReaderSubMode(null); setErr(""); }}>חזרה</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════
//  LIBRARIAN DASHBOARD
// ═══════════════════════════════════════════════════════
function LibrarianDashboard({ books, readers, loans, updateAll, page, setPage, showToast, librarianPin, setLibrarianPin }) {
  const pages = [
    { id: "overview", icon: "📊", label: "סקירה" },
    { id: "books", icon: "📚", label: "ספרים" },
    { id: "loans", icon: "📋", label: "השאלות" },
    { id: "readers", icon: "👥", label: "מנויים" },
    { id: "search_book", icon: "🔍", label: "חיפוש ספר" },
    { id: "settings", icon: "⚙️", label: "הגדרות" },
  ];

  useEffect(() => { if (page === "home") setPage("overview"); }, []);

  return (
    <div className="dashboard">
      <nav className="sidebar">
        {pages.map(p => (
          <div key={p.id} className={`sidebar-item ${page === p.id ? "active" : ""}`} onClick={() => setPage(p.id)}>
            <span>{p.icon}</span><span>{p.label}</span>
          </div>
        ))}
        <div className="sidebar-divider" />
      </nav>
      <main className="main-content">
        {page === "overview" && <Overview books={books} readers={readers} loans={loans} />}
        {page === "books" && <BooksManager books={books} loans={loans} updateAll={b => updateAll(b, readers, loans)} showToast={showToast} />}
        {page === "loans" && <LoansManager books={books} readers={readers} loans={loans} updateAll={(l) => updateAll(books, readers, l)} showToast={showToast} />}
        {page === "readers" && <ReadersManager readers={readers} updateAll={r => updateAll(books, r, loans)} showToast={showToast} />}
        {page === "search_book" && <BookSearch books={books} loans={loans} readers={readers} />}
        {page === "settings" && <LibrarianSettings librarianPin={librarianPin} setLibrarianPin={setLibrarianPin} showToast={showToast} />}
      </main>
    </div>
  );
}

// ── OVERVIEW ──
function Overview({ books, readers, loans }) {
  const today = new Date().toISOString().split("T")[0];
  const activeLoans = loans.filter(l => !l.returned);
  const overdue = activeLoans.filter(l => l.returnDate < today);
  const available = books.length - new Set(activeLoans.map(l => l.bookId)).size;

  return (
    <div>
      <div className="section-header"><h2 className="section-title">סקירה כללית</h2></div>
      <div className="stats-row">
        <div className="stat-card"><div className="stat-number">{books.length}</div><div className="stat-label">ספרים במאגר</div></div>
        <div className="stat-card"><div className="stat-number">{available}</div><div className="stat-label">זמינים להשאלה</div></div>
        <div className="stat-card"><div className="stat-number">{readers.length}</div><div className="stat-label">מנויים רשומים</div></div>
        <div className="stat-card"><div className="stat-number">{activeLoans.length}</div><div className="stat-label">השאלות פעילות</div></div>
        <div className="stat-card"><div className="stat-number" style={{ color: overdue.length ? "var(--rust)" : "var(--sage)" }}>{overdue.length}</div><div className="stat-label">באיחור</div></div>
      </div>
      {overdue.length > 0 && (
        <div style={{ background:"#fff5f5", border:"1.5px solid var(--rust)", borderRadius:"3px", padding:"1rem", marginTop:"1rem" }}>
          <strong style={{ fontFamily:"'Alef',Arial,sans-serif", fontWeight:700, color:"var(--rust)" }}>⚠️ ספרים באיחור:</strong>
          <ul style={{ marginTop:"0.5rem", paddingRight:"1rem" }}>
            {overdue.map(l => <li key={l.id} style={{ fontSize:"0.9rem", marginTop:"0.2rem" }}>
              יש להחזיר עד {l.returnDate}
            </li>)}
          </ul>
        </div>
      )}
    </div>
  );
}

// ── BOOKS MANAGER ──
function BooksManager({ books, loans, updateAll, showToast }) {
  const [showAdd, setShowAdd] = useState(false);
  const [editBook, setEditBook] = useState(null);
  const [search, setSearch] = useState("");

  const activeLoans = loans.filter(l => !l.returned);
  const loanedIds = new Set(activeLoans.map(l => l.bookId));

  const filtered = books.filter(b =>
    b.title.includes(search) || b.author.includes(search)
  );

  const addBook = (book) => {
    const newBooks = [...books, { ...book, id: "b" + Date.now(), addedAt: new Date().toISOString().split("T")[0] }];
    updateAll(newBooks);
    setShowAdd(false);
    showToast("✓ הספר נוסף בהצלחה");
  };

  const deleteBook = (id) => {
    if (loanedIds.has(id)) { showToast("❌ לא ניתן למחוק ספר מושאל"); return; }
    updateAll(books.filter(b => b.id !== id));
    showToast("✓ הספר הוסר");
  };

  const saveEdit = (updated) => {
    updateAll(books.map(b => b.id === updated.id ? updated : b));
    setEditBook(null);
    showToast("✓ הספר עודכן בהצלחה");
  };

  return (
    <div>
      <div className="section-header">
        <h2 className="section-title">מאגר ספרים <span className="section-count">({books.length})</span></h2>
        <button className="btn btn-primary" onClick={() => setShowAdd(true)}>+ הוסף ספר</button>
      </div>
      <div className="search-bar">
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="חיפוש לפי שם ספר / סופר..." />
        <span className="search-icon">🔍</span>
      </div>
      <div className="books-grid">
        {filtered.map(b => (
          <div key={b.id} className="book-card">
            <div className="book-cover">
              {b.cover ? <img src={b.cover} alt={b.title} /> : "📖"}
              <div className="book-cover-label">{loanedIds.has(b.id) ? "LOANED" : "AVAILABLE"}</div>
            </div>
            <div className="book-info">
              <div className="book-title">{b.title}</div>
              <div className="book-author">{b.author}</div>
              <div>
                <span className={`book-badge ${loanedIds.has(b.id) ? "badge-loaned" : "badge-available"}`}>
                  {loanedIds.has(b.id) ? "מושאל" : "זמין"}
                </span>
              </div>
              <div style={{ marginTop:"0.4rem", display:"flex", gap:"0.5rem" }}>
                <button className="btn-link" style={{ color:"var(--rust)", fontSize:"0.8rem" }} onClick={() => setEditBook(b)}>✏️ עריכה</button>
                <button className="btn-link" onClick={() => deleteBook(b.id)} style={{ color:"#c0392b", fontSize:"0.8rem" }}>הסר</button>
              </div>
            </div>
          </div>
        ))}
        {filtered.length === 0 && <div className="empty-state" style={{ gridColumn:"1/-1" }}>לא נמצאו ספרים</div>}
      </div>
      {showAdd && <AddBookModal onAdd={addBook} onClose={() => setShowAdd(false)} />}
      {editBook && <EditBookModal book={editBook} onSave={saveEdit} onClose={() => setEditBook(null)} />}
    </div>
  );
}

// ── ADD BOOK MODAL ──
function AddBookModal({ onAdd, onClose }) {
  const [tab, setTab] = useState("scan");
  const [status, setStatus] = useState("");
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);
  const [title, setTitle] = useState("");
  const [author, setAuthor] = useState("");
  const [coverPreview, setCoverPreview] = useState(null);
  const [query, setQuery] = useState("");
  const fileRef = useRef();

  const reset = () => { setStatus(""); setError(""); };

  const handleImageFile = async (file) => {
    if (!file) return;
    setBusy(true); reset();
    setStatus("🗜️ מכין תמונה...");
    try {
      // Resize image to max 1200px and compress to stay under 5MB
      const resized = await resizeImage(file, 1200, 0.85);
      const b64 = resized.b64;
      const mt = resized.mt;
      setCoverPreview("data:" + mt + ";base64," + b64);
      try {
        const result = await identifyBookFromImage(b64, mt, setStatus);
        if (result && (result.title || result.author)) {
          if (result.title) setTitle(result.title);
          if (result.author) setAuthor(result.author);
          setStatus("✓ זוהה בהצלחה! בדקי את הפרטים למטה");
        } else {
          setError("לא הצלחתי לזהות — עברי לחיפוש ברשת או הזנה ידנית");
          setStatus("");
        }
      } catch (err) {
        console.error("Scan error:", err);
        setError("שגיאה: " + err.message);
        setStatus("");
      }
    } catch (err) {
      setError("שגיאה בעיבוד התמונה: " + err.message);
      setStatus("");
    }
    setBusy(false);
  };

  const handleSearch = async () => {
    if (!query.trim()) return;
    setBusy(true); reset();
    try {
      const result = await searchBookByTitle(query, setStatus);
      if (result && (result.title || result.author)) {
        if (result.title) setTitle(result.title);
        if (result.author) setAuthor(result.author);
        setStatus("✓ נמצא! בדקי את הפרטים למטה");
      } else {
        setError("לא נמצאו תוצאות — נסי מילות חיפוש אחרות");
        setStatus("");
      }
    } catch (err) {
      setError("שגיאת חיפוש — נסי הזנה ידנית");
      setStatus("");
    }
    setBusy(false);
  };

  const submit = () => {
    if (!title.trim()) return;
    onAdd({ title: title.trim(), author: author.trim(), cover: coverPreview });
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <h3 className="modal-title">הוספת ספר חדש</h3>
        <div className="tabs">
          <div className={`tab ${tab === "scan" ? "active" : ""}`} onClick={() => { setTab("scan"); reset(); }}>📷 צילום כריכה</div>
          <div className={`tab ${tab === "search" ? "active" : ""}`} onClick={() => { setTab("search"); reset(); }}>🔍 חיפוש ברשת</div>
          <div className={`tab ${tab === "manual" ? "active" : ""}`} onClick={() => { setTab("manual"); reset(); }}>✍️ ידני</div>
        </div>

        {tab === "scan" && (
          <div style={{ marginBottom:"1rem" }}>
            <div className="scan-area" onClick={() => !busy && fileRef.current.click()}>
              {coverPreview
                ? <img src={coverPreview} className="scan-preview" alt="כריכה" />
                : <><div className="scan-icon">📷</div>
                  <p>לחצי לצילום או העלאת תמונת כריכה</p>
                  <p style={{ fontSize:"0.8rem", color:"#aaa", marginTop:"0.3rem" }}>Claude יקרא את הטקסט על הכריכה ישירות</p></>
              }
            </div>
            <input ref={fileRef} type="file" accept="image/*" capture="environment" style={{ display:"none" }}
              onChange={e => handleImageFile(e.target.files[0])} />
          </div>
        )}

        {tab === "search" && (
          <div style={{ marginBottom:"1rem" }}>
            <p style={{ fontSize:"0.85rem", color:"#888", marginBottom:"0.7rem" }}>הקלידי שם ספר ו/או סופר לחיפוש ברשת</p>
            <div style={{ display:"flex", gap:"0.5rem" }}>
              <input value={query} onChange={e => setQuery(e.target.value)}
                onKeyDown={e => e.key === "Enter" && !busy && handleSearch()}
                placeholder='לדוגמה: "לילית ואחרים פרימו לוי"'
                style={{ flex:1, padding:"0.6rem 0.8rem", border:"1.5px solid #ccc", borderRadius:"2px",
                  fontFamily:"'Alef',Arial,sans-serif", fontSize:"1rem", direction:"rtl", background:"var(--paper)" }} />
              <button className="btn btn-primary" onClick={handleSearch} disabled={busy || !query.trim()}>חפש</button>
            </div>
          </div>
        )}

        {busy && (
          <div style={{ background:"var(--cream)", border:"1px solid var(--gold)", borderRadius:"3px",
            padding:"0.6rem 1rem", marginBottom:"0.8rem", fontSize:"0.9rem", color:"var(--rust)" }}>
            ⏳ {status}
          </div>
        )}
        {!busy && status && (
          <div style={{ background:"#f0f8f0", border:"1px solid var(--sage)", borderRadius:"3px",
            padding:"0.6rem 1rem", marginBottom:"0.8rem", fontSize:"0.9rem", color:"var(--sage)" }}>
            {status}
          </div>
        )}
        {error && (
          <p style={{ color:"var(--rust)", fontSize:"0.85rem", marginBottom:"0.8rem" }}>⚠️ {error}</p>
        )}

        <div className="form-group">
          <label>שם הספר *</label>
          <input value={title} onChange={e => setTitle(e.target.value)} placeholder="שם הספר" />
        </div>
        <div className="form-group">
          <label>שם הסופר</label>
          <input value={author} onChange={e => setAuthor(e.target.value)} placeholder="שם הסופר" />
        </div>

        {tab !== "scan" && (
          <div className="form-group">
            <label>תמונת כריכה (אופציונלי)</label>
            <div className="scan-area" style={{ padding:"0.8rem" }} onClick={() => fileRef.current.click()}>
              {coverPreview
                ? <img src={coverPreview} style={{ maxHeight:100, maxWidth:"100%", borderRadius:3 }} alt="" />
                : <><div style={{ fontSize:"1.2rem" }}>📷</div><p style={{ fontSize:"0.8rem", color:"#aaa" }}>הוספת תמונת כריכה</p></>
              }
            </div>
            <input ref={fileRef} type="file" accept="image/*" style={{ display:"none" }} onChange={e => { const f=e.target.files[0]; if(f){const r=new FileReader();r.onload=ev=>setCoverPreview(ev.target.result);r.readAsDataURL(f);}}} />
          </div>
        )}

        <div className="modal-actions">
          <button className="btn btn-primary" onClick={submit} disabled={!title.trim() || busy}>הוסף ספר</button>
          <button className="btn btn-secondary" onClick={onClose}>ביטול</button>
        </div>
      </div>
    </div>
  );
}

// ── EDIT BOOK MODAL ──
function EditBookModal({ book, onSave, onClose }) {
  const [title, setTitle] = useState(book.title);
  const [author, setAuthor] = useState(book.author);
  const [coverPreview, setCoverPreview] = useState(book.cover || null);
  const [status, setStatus] = useState("");
  const [busy, setBusy] = useState(false);
  const fileRef = useRef();

  const handleImageFile = async (file) => {
    if (!file) return;
    setBusy(true); setStatus("🗜️ מכין תמונה...");
    try {
      const resized = await resizeImage(file, 1200, 0.85);
      setCoverPreview("data:" + resized.mt + ";base64," + resized.b64);
      const result = await identifyBookFromImage(resized.b64, resized.mt, setStatus);
      if (result?.title) setTitle(result.title);
      if (result?.author) setAuthor(result.author);
      setStatus("✓ זוהה בהצלחה! בדוק/י את הפרטים");
    } catch {
      setStatus("⚠️ שגיאה בעיבוד התמונה");
    }
    setBusy(false);
  };

  const submit = () => {
    if (!title.trim()) return;
    onSave({ ...book, title: title.trim(), author: author.trim(), cover: coverPreview });
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <h3 className="modal-title">✏️ עריכת ספר</h3>

        {/* Cover */}
        <div className="form-group">
          <label>כריכה</label>
          <div className="scan-area" style={{ padding:"0.8rem", cursor:"pointer" }} onClick={() => !busy && fileRef.current.click()}>
            {coverPreview
              ? <img src={coverPreview} style={{ maxHeight:100, maxWidth:"100%", borderRadius:3 }} alt="כריכה" />
              : <><div style={{ fontSize:"1.5rem" }}>📷</div><p style={{ fontSize:"0.8rem", color:"#aaa" }}>לחץ/י להחלפת תמונה</p></>}
          </div>
          <input ref={fileRef} type="file" accept="image/*" style={{ display:"none" }}
            onChange={e => handleImageFile(e.target.files[0])} />
          {coverPreview && (
            <button className="btn-link" style={{ fontSize:"0.8rem", color:"#c0392b", marginTop:"0.3rem" }}
              onClick={() => setCoverPreview(null)}>✕ הסר תמונה</button>
          )}
        </div>

        {busy && (
          <div style={{ background:"var(--cream)", border:"1px solid var(--gold)", borderRadius:"3px",
            padding:"0.5rem 0.8rem", marginBottom:"0.8rem", fontSize:"0.85rem", color:"var(--rust)" }}>
            ⏳ {status}
          </div>
        )}
        {!busy && status && (
          <div style={{ background:"#f0f8f0", border:"1px solid var(--sage)", borderRadius:"3px",
            padding:"0.5rem 0.8rem", marginBottom:"0.8rem", fontSize:"0.85rem", color:"var(--sage)" }}>
            {status}
          </div>
        )}

        <div className="form-group">
          <label>שם הספר *</label>
          <input value={title} onChange={e => setTitle(e.target.value)} placeholder="שם הספר" />
        </div>
        <div className="form-group">
          <label>שם הסופר/ת</label>
          <input value={author} onChange={e => setAuthor(e.target.value)} placeholder="שם הסופר/ת" />
        </div>

        <div className="modal-actions">
          <button className="btn btn-primary" onClick={submit} disabled={!title.trim() || busy}>שמור שינויים</button>
          <button className="btn btn-secondary" onClick={onClose}>ביטול</button>
        </div>
      </div>
    </div>
  );
}

// ── LOANS MANAGER ──
function LoansManager({ books, readers, loans, updateAll, showToast }) {
  const [showAdd, setShowAdd] = useState(false);
  const [search, setSearch] = useState("");
  const today = new Date().toISOString().split("T")[0];

  const matchesSearch = (l) => {
    if (!search.trim()) return true;
    const q = search.trim();
    const book = books.find(b => b.id === l.bookId);
    const reader = readers.find(r => r.id === l.readerId);
    return (
      book?.title?.includes(q) ||
      book?.author?.includes(q) ||
      reader?.firstName?.includes(q) ||
      reader?.lastName?.includes(q) ||
      reader?.phone?.includes(q)
    );
  };

  const active = loans.filter(l => !l.returned && matchesSearch(l));
  const returned = loans.filter(l => l.returned && matchesSearch(l));

  const returnBook = (loanId) => {
    updateAll(loans.map(l => l.id === loanId ? { ...l, returned: true } : l));
    showToast("✓ ספר הוחזר בהצלחה");
  };

  const addLoan = (loan) => {
    updateAll([...loans, { ...loan, id: "l" + Date.now(), returned: false }]);
    setShowAdd(false);
    showToast("✓ השאלה נרשמה");
  };

  const getBook = id => books.find(b => b.id === id);
  const getReader = id => readers.find(r => r.id === id);

  const renderTable = (list) => (
    list.length === 0 ? <div className="empty-state">אין נתונים</div> :
    <div style={{ overflowX:"auto" }}>
      <table className="data-table">
        <thead><tr>
          <th>ספר</th><th>קורא</th><th>תאריך השאלה</th><th>תאריך החזרה</th><th>סטטוס</th><th>פעולה</th>
        </tr></thead>
        <tbody>
          {list.map(l => {
            const overdue = !l.returned && l.returnDate < today;
            const b = getBook(l.bookId); const r = getReader(l.readerId);
            return (
              <tr key={l.id} className={overdue ? "overdue" : ""}>
                <td>{b?.title || "?"}</td>
                <td>{r ? `${r.firstName} ${r.lastName}` : "?"}</td>
                <td>{l.loanDate}</td>
                <td>{l.returnDate}</td>
                <td>
                  {l.returned ? <span style={{ color:"var(--sage)" }}>✓ הוחזר</span>
                   : overdue ? <span style={{ color:"var(--rust)" }}>⚠️ באיחור</span>
                   : <span style={{ color:"var(--sage)" }}>פעיל</span>}
                </td>
                <td>
                  {!l.returned && <button className="btn btn-sm btn-success" onClick={() => returnBook(l.id)}>החזרה</button>}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );

  return (
    <div>
      <div className="section-header">
        <h2 className="section-title">השאלות</h2>
        <button className="btn btn-primary" onClick={() => setShowAdd(true)}>+ השאלה חדשה</button>
      </div>
      <div className="search-bar" style={{ maxWidth:"400px" }}>
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="חיפוש לפי ספר, סופר, מנוי..." />
        <span className="search-icon">🔍</span>
      </div>
      <h3 style={{ fontFamily:"'Alef',Arial,sans-serif", fontWeight:700, fontSize:"1rem", color:"var(--stamp)", marginBottom:"0.7rem" }}>📋 השאלות פעילות ({active.length})</h3>
      {renderTable(active)}
      <h3 style={{ fontFamily:"'Alef',Arial,sans-serif", fontWeight:700, fontSize:"1rem", color:"var(--stamp)", margin:"1.5rem 0 0.7rem" }}>📁 היסטוריה ({returned.length})</h3>
      {renderTable(returned)}
      {showAdd && <AddLoanModal books={books} readers={readers} loans={loans} onAdd={addLoan} onClose={() => setShowAdd(false)} />}
    </div>
  );
}

function AddLoanModal({ books, readers, loans, onAdd, onClose }) {
  const activeLoans = loans.filter(l => !l.returned);
  const loanedIds = new Set(activeLoans.map(l => l.bookId));
  const available = books.filter(b => !loanedIds.has(b.id));
  const today = new Date().toISOString().split("T")[0];
  const twoWeeks = new Date(Date.now() + 14 * 86400000).toISOString().split("T")[0];
  const [form, setForm] = useState({ bookId:"", readerId:"", loanDate: today, returnDate: twoWeeks });
  const [bookSearch, setBookSearch] = useState("");

  const set = (k,v) => setForm(f => ({...f,[k]:v}));

  const filteredBooks = available.filter(b =>
    !bookSearch.trim() ||
    b.title.includes(bookSearch.trim()) ||
    b.author.includes(bookSearch.trim())
  );

  const selectedBook = books.find(b => b.id === form.bookId);

  const submit = () => {
    if (!form.bookId || !form.readerId || !form.returnDate) return;
    onAdd(form);
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <h3 className="modal-title">השאלת ספר חדשה</h3>
        <div className="form-group">
          <label>ספר</label>
          {selectedBook ? (
            <div style={{ display:"flex", gap:"0.5rem", alignItems:"center" }}>
              <span style={{ flex:1, padding:"0.4rem 0.6rem", border:"1px solid #ccc", borderRadius:"3px", background:"#f9f6f1" }}>
                {selectedBook.title} — {selectedBook.author}
              </span>
              <button className="btn btn-sm btn-secondary" onClick={() => { set("bookId",""); setBookSearch(""); }}>שנה</button>
            </div>
          ) : (
            <>
              <input
                value={bookSearch}
                onChange={e => setBookSearch(e.target.value)}
                placeholder="חפש/י שם ספר או סופר..."
                style={{ marginBottom:"0.4rem" }}
                autoFocus
              />
              <select size={5} value={form.bookId} onChange={e => { set("bookId", e.target.value); setBookSearch(""); }}
                style={{ width:"100%", borderRadius:"3px", border:"1px solid #ccc" }}>
                <option value="">בחר ספר...</option>
                {filteredBooks.map(b => <option key={b.id} value={b.id}>{b.title} — {b.author}</option>)}
              </select>
            </>
          )}
        </div>
        <div className="form-group">
          <label>מנוי</label>
          <select value={form.readerId} onChange={e => set("readerId",e.target.value)}>
            <option value="">בחר מנוי...</option>
            {readers.map(r => <option key={r.id} value={r.id}>{r.firstName} {r.lastName}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label>תאריך השאלה</label>
          <input type="date" value={form.loanDate} onChange={e => set("loanDate",e.target.value)} />
        </div>
        <div className="form-group">
          <label>תאריך החזרה</label>
          <input type="date" value={form.returnDate} onChange={e => set("returnDate",e.target.value)} min={today} />
        </div>
        <div className="modal-actions">
          <button className="btn btn-primary" onClick={submit} disabled={!form.bookId || !form.readerId || !form.returnDate}>אשר השאלה</button>
          <button className="btn btn-secondary" onClick={onClose}>ביטול</button>
        </div>
      </div>
    </div>
  );
}

// ── READERS MANAGER ──
function ReadersManager({ readers, updateAll, showToast }) {
  const [showAdd, setShowAdd] = useState(false);
  const [search, setSearch] = useState("");
  const [form, setForm] = useState({ firstName:"", lastName:"", phone:"", pin:"" });
  const [editPinId, setEditPinId] = useState(null);
  const [newPin, setNewPin] = useState("");
  const set = (k,v) => setForm(f => ({...f,[k]:v}));

  const filtered = readers.filter(r => {
    if (!search.trim()) return true;
    const q = search.trim();
    return r.firstName?.includes(q) || r.lastName?.includes(q) || r.phone?.includes(q);
  });

  const addReader = () => {
    if (!form.firstName || !form.phone || !form.pin) return;
    updateAll([...readers, { ...form, id: "r" + Date.now() }]);
    setForm({ firstName:"", lastName:"", phone:"", pin:"" });
    setShowAdd(false);
    showToast("✓ מנוי נוסף בהצלחה");
  };

  const remove = (id) => {
    updateAll(readers.filter(r => r.id !== id));
    showToast("✓ מנוי הוסר");
  };

  const savePin = (id) => {
    if (!newPin || newPin.length !== 4 || !/^\d{4}$/.test(newPin)) {
      showToast("❌ קוד חייב להיות 4 ספרות"); return;
    }
    updateAll(readers.map(r => r.id === id ? { ...r, pin: newPin } : r));
    setEditPinId(null);
    setNewPin("");
    showToast("✓ קוד עודכן בהצלחה");
  };

  return (
    <div>
      <div className="section-header">
        <h2 className="section-title">מנויים <span className="section-count">({readers.length})</span></h2>
        <button className="btn btn-primary" onClick={() => setShowAdd(true)}>+ מנוי חדש</button>
      </div>
      <div className="search-bar" style={{ maxWidth:"400px" }}>
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="חיפוש לפי שם או טלפון..." />
        <span className="search-icon">🔍</span>
      </div>
      <div style={{ overflowX:"auto" }}>
        <table className="data-table">
          <thead><tr><th>שם פרטי</th><th>שם משפחה</th><th>טלפון</th><th>קוד</th><th>פעולות</th></tr></thead>
          <tbody>
            {filtered.map(r => (
              <tr key={r.id}>
                <td>{r.firstName}</td><td>{r.lastName}</td><td>{r.phone}</td>
                <td>
                  {editPinId === r.id ? (
                    <div style={{ display:"flex", gap:"0.4rem", alignItems:"center" }}>
                      <input type="password" value={newPin} onChange={e => setNewPin(e.target.value)}
                        maxLength={4} placeholder="קוד חדש" style={{ width:"80px", padding:"0.2rem 0.4rem", border:"1px solid #ccc", borderRadius:"3px" }} />
                      <button className="btn btn-sm btn-primary" onClick={() => savePin(r.id)}>שמור</button>
                      <button className="btn btn-sm btn-secondary" onClick={() => { setEditPinId(null); setNewPin(""); }}>ביטול</button>
                    </div>
                  ) : (
                    <span style={{ letterSpacing:"2px", fontFamily:"monospace" }}>{r.pin}</span>
                  )}
                </td>
                <td style={{ display:"flex", gap:"0.4rem" }}>
                  <button className="btn btn-sm btn-secondary" onClick={() => { setEditPinId(r.id); setNewPin(""); }}>✏️ קוד</button>
                  <button className="btn btn-sm btn-danger" onClick={() => remove(r.id)}>הסר</button>
                </td>
              </tr>
            ))}
            {filtered.length === 0 && <tr><td colSpan={5} style={{ textAlign:"center", color:"#aaa", padding:"1rem" }}>לא נמצאו מנויים</td></tr>}
          </tbody>
        </table>
      </div>
      {showAdd && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setShowAdd(false)}>
          <div className="modal">
            <h3 className="modal-title">הוספת מנוי חדש</h3>
            {[["firstName","שם פרטי"],["lastName","שם משפחה"]].map(([k,l]) => (
              <div className="form-group" key={k}>
                <label>{l}</label>
                <input value={form[k]} onChange={e => set(k,e.target.value)} placeholder={l} />
              </div>
            ))}
            <div className="form-group">
              <label>טלפון</label>
              <input value={form.phone} onChange={e => set("phone", formatPhone(e.target.value))} placeholder="052-1234567" />
            </div>
            <div className="form-group">
              <label>קוד אישי (4 ספרות)</label>
              <input type="password" value={form.pin} onChange={e => set("pin",e.target.value)} maxLength={4} placeholder="••••" />
            </div>
            <div className="modal-actions">
              <button className="btn btn-primary" onClick={addReader}>הוסף</button>
              <button className="btn btn-secondary" onClick={() => setShowAdd(false)}>ביטול</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── LIBRARIAN SETTINGS ──
function LibrarianSettings({ librarianPin, setLibrarianPin, showToast }) {
  const [oldPin, setOldPin] = useState("");
  const [newPin, setNewPin] = useState("");
  const [confirmPin, setConfirmPin] = useState("");
  const [err, setErr] = useState("");

  const save = () => {
    setErr("");
    if (oldPin !== librarianPin) { setErr("הקוד הנוכחי שגוי"); return; }
    if (newPin.length < 4 || !/^\d+$/.test(newPin)) { setErr("קוד חדש חייב להיות ספרות בלבד (לפחות 4)"); return; }
    if (newPin !== confirmPin) { setErr("הקודים החדשים אינם תואמים"); return; }
    setLibrarianPin(newPin);
    setOldPin(""); setNewPin(""); setConfirmPin("");
    showToast("✓ קוד הספרנית עודכן בהצלחה");
  };

  return (
    <div>
      <div className="section-header">
        <h2 className="section-title">הגדרות</h2>
      </div>
      <div style={{ maxWidth:"400px", background:"white", border:"1.5px solid #ddd", borderRadius:"4px", padding:"1.5rem", boxShadow:"2px 2px 0 var(--shadow)" }}>
        <h3 style={{ fontFamily:"'Alef',Arial,sans-serif", fontWeight:700, marginBottom:"1.2rem", color:"var(--ink)" }}>🔐 שינוי קוד הספרנית</h3>
        <div className="form-group">
          <label>קוד נוכחי</label>
          <input type="password" value={oldPin} onChange={e => setOldPin(e.target.value)} placeholder="הזיני קוד נוכחי" />
        </div>
        <div className="form-group">
          <label>קוד חדש</label>
          <input type="password" value={newPin} onChange={e => setNewPin(e.target.value)} placeholder="קוד חדש (ספרות בלבד)" />
        </div>
        <div className="form-group">
          <label>אימות קוד חדש</label>
          <input type="password" value={confirmPin} onChange={e => setConfirmPin(e.target.value)} placeholder="הזיני שוב את הקוד החדש" />
        </div>
        {err && <p style={{ color:"var(--rust)", marginBottom:"0.8rem", fontSize:"0.9rem" }}>{err}</p>}
        <button className="btn btn-primary" onClick={save}>שמור קוד חדש</button>
      </div>
    </div>
  );
}

// ── BOOK SEARCH ──
function BookSearch({ books, loans, readers }) {
  const [q, setQ] = useState("");
  const activeLoans = loans.filter(l => !l.returned);
  const loanMap = Object.fromEntries(activeLoans.map(l => [l.bookId, l]));

  const results = q.trim() ? books.filter(b => b.title.includes(q) || b.author.includes(q)) : [];

  return (
    <div>
      <div className="section-header"><h2 className="section-title">חיפוש ספר</h2></div>
      <div className="search-bar" style={{ maxWidth:"500px" }}>
        <input value={q} onChange={e => setQ(e.target.value)} placeholder="הקלד/י שם ספר או סופר..." autoFocus />
        <span className="search-icon">🔍</span>
      </div>
      {results.map(b => {
        const loan = loanMap[b.id];
        const reader = loan ? readers.find(r => r.id === loan.readerId) : null;
        return (
          <div key={b.id} style={{ background:"white", border:"1.5px solid #ddd", borderRadius:"3px", padding:"1rem 1.2rem", marginBottom:"0.7rem", boxShadow:"2px 2px 0 var(--shadow)" }}>
            <strong style={{ fontFamily:"'Alef',Arial,sans-serif", fontWeight:700, fontSize:"1.1rem" }}>{b.title}</strong>
            <div style={{ color:"#888", fontStyle:"italic", marginBottom:"0.5rem" }}>{b.author}</div>
            {loan ? (
              <div>
                <span className="book-badge badge-loaned">מושאל</span>
                {reader && <span style={{ fontSize:"0.9rem", marginRight:"0.7rem" }}>אצל: {reader.firstName} {reader.lastName}</span>}
                <span style={{ fontSize:"0.85rem", color:"#888", marginRight:"0.7rem" }}>יחזיר עד: {loan.returnDate}</span>
              </div>
            ) : <span className="book-badge badge-available">זמין להשאלה</span>}
          </div>
        );
      })}
      {q.trim() && results.length === 0 && <div className="empty-state">לא נמצאו ספרים מתאימים</div>}
    </div>
  );
}

// ═══════════════════════════════════════════════════════
//  READER DASHBOARD
// ═══════════════════════════════════════════════════════
function ReaderDashboard({ books, readers, loans, updateAll, readerId, page, setPage, showToast }) {
  const reader = readers.find(r => r.id === readerId);
  const myLoans = loans.filter(l => l.readerId === readerId);
  const active = myLoans.filter(l => !l.returned);
  const history = myLoans.filter(l => l.returned);
  const today = new Date().toISOString().split("T")[0];

  const [editMode, setEditMode] = useState(false);
  const [form, setForm] = useState({ firstName: reader?.firstName || "", lastName: reader?.lastName || "", phone: reader?.phone || "", pin: reader?.pin || "" });
  const set = (k,v) => setForm(f => ({...f,[k]:v}));

  const saveProfile = () => {
    const updated = readers.map(r => r.id === readerId ? { ...r, ...form } : r);
    updateAll(books, updated, loans);
    setEditMode(false);
    showToast("✓ הפרטים עודכנו");
  };

  useEffect(() => { if (page === "home") setPage("my_loans"); }, []);

  const ALERT_DAYS = 3;
  const alerts = active.filter(l => {
    const daysLeft = Math.ceil((new Date(l.returnDate) - new Date()) / 86400000);
    return daysLeft <= ALERT_DAYS;
  });

  const pages = [
    { id: "my_loans", icon: "📋", label: "ספרים שלי" },
    { id: "history", icon: "📁", label: "היסטוריה" },
    { id: "profile", icon: "👤", label: "הפרופיל שלי" },
    { id: "catalog", icon: "📚", label: "קטלוג" },
  ];

  const getBook = id => books.find(b => b.id === id);

  const LoanItem = ({ loan }) => {
    const book = getBook(loan.bookId);
    const overdue = loan.returnDate < today;
    const daysLeft = Math.ceil((new Date(loan.returnDate) - new Date()) / 86400000);
    return (
      <div className={`loan-card ${overdue ? "overdue" : ""}`}>
        <div className="loan-book-icon">{book?.cover ? <img src={book.cover} style={{ width:48, height:60, objectFit:"cover", borderRadius:2 }} alt="" /> : "📖"}</div>
        <div className="loan-info">
          <div className="loan-title">{book?.title || "ספר לא ידוע"}</div>
          <div style={{ fontSize:"0.85rem", color:"#888", fontStyle:"italic" }}>{book?.author}</div>
          <div className="loan-dates">הושאל: {loan.loanDate} | יש להחזיר: {loan.returnDate}</div>
          <div className="loan-days">
            {overdue
              ? <span className="overdue-text">⚠️ באיחור של {Math.abs(daysLeft)} ימים!</span>
              : <span className="ok-text">✓ נותרו {daysLeft} ימים להחזרה</span>}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="dashboard">
      <nav className="sidebar">
        <div style={{ padding:"0.5rem 0.8rem 0.3rem", color:"#b8a070", fontSize:"0.8rem", fontFamily:"'Alef',Arial,sans-serif", fontWeight:700 }}>
          שלום {reader?.firstName}!
        </div>
        <div className="sidebar-divider" />
        {pages.map(p => (
          <div key={p.id} className={`sidebar-item ${page === p.id ? "active" : ""}`} onClick={() => setPage(p.id)}
            style={{ position:"relative" }}>
            <span>{p.icon}</span>
            <span>{p.label}</span>
            {p.id === "my_loans" && alerts.length > 0 && (
              <span style={{
                position:"absolute", top:6, left:8,
                background:"#e74c3c", color:"white",
                borderRadius:"50%", width:18, height:18,
                fontSize:"0.7rem", fontWeight:700,
                display:"flex", alignItems:"center", justifyContent:"center",
                lineHeight:1,
              }}>{alerts.length}</span>
            )}
          </div>
        ))}
      </nav>
      <main className="main-content">
        {page === "my_loans" && (
          <div>
            <div className="section-header"><h2 className="section-title">הספרים שלי ({active.length})</h2></div>

            {/* Alerts banner */}
            {alerts.length > 0 && (
              <div style={{
                background:"#fff8e6", border:"2px solid var(--gold)",
                borderRadius:"4px", padding:"0.9rem 1.1rem",
                marginBottom:"1.2rem",
              }}>
                <div style={{ fontFamily:"'Alef',Arial,sans-serif", fontWeight:700, color:"var(--rust)", marginBottom:"0.5rem", fontSize:"1rem" }}>
                  🔔 תזכורת החזרה
                </div>
                {alerts.map(l => {
                  const book = getBook(l.bookId);
                  const daysLeft = Math.ceil((new Date(l.returnDate) - new Date()) / 86400000);
                  const overdue = daysLeft < 0;
                  return (
                    <div key={l.id} style={{
                      display:"flex", alignItems:"center", gap:"0.6rem",
                      padding:"0.4rem 0", borderTop:"1px solid #f0e0b0",
                      fontSize:"0.9rem",
                    }}>
                      <span style={{ fontSize:"1.1rem" }}>{overdue ? "⚠️" : "⏰"}</span>
                      <span style={{ fontWeight:700, color:"var(--stamp)" }}>{book?.title}</span>
                      <span style={{ color: overdue ? "var(--rust)" : "#b07d00", marginRight:"auto" }}>
                        {overdue
                          ? `באיחור של ${Math.abs(daysLeft)} ימים!`
                          : daysLeft === 0
                            ? "יש להחזיר היום!"
                            : `יש להחזיר בעוד ${daysLeft} ימים`}
                      </span>
                    </div>
                  );
                })}
              </div>
            )}

            <div className="my-loans">
              {active.length === 0 ? <div className="empty-state">אין ספרים מושאלים כעת</div> : active.map(l => <LoanItem key={l.id} loan={l} />)}
            </div>
          </div>
        )}
        {page === "history" && (
          <div>
            <div className="section-header"><h2 className="section-title">היסטוריית השאלות ({history.length})</h2></div>
            <div className="my-loans">
              {history.length === 0 ? <div className="empty-state">אין היסטוריית השאלות</div>
               : history.map(l => {
                const book = getBook(l.bookId);
                return (
                  <div key={l.id} className="loan-card" style={{ opacity:0.75 }}>
                    <div className="loan-book-icon">📖</div>
                    <div className="loan-info">
                      <div className="loan-title">{book?.title}</div>
                      <div className="loan-dates">{l.loanDate} – {l.returnDate}</div>
                      <div style={{ fontSize:"0.85rem", color:"var(--sage)" }}>✓ הוחזר</div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
        {page === "profile" && (
          <div>
            <div className="section-header">
              <h2 className="section-title">הפרופיל שלי</h2>
              {!editMode && <button className="btn btn-secondary" onClick={() => setEditMode(true)}>✏️ עריכה</button>}
            </div>
            <div className="login-form" style={{ maxWidth:"400px" }}>
              {editMode ? (
                <>
                  {[["firstName","שם פרטי"],["lastName","שם משפחה"]].map(([k,l]) => (
                    <div className="form-group" key={k}><label>{l}</label>
                      <input value={form[k]} onChange={e => set(k, e.target.value)} /></div>
                  ))}
                  <div className="form-group"><label>טלפון</label>
                    <input value={form.phone} onChange={e => set("phone", formatPhone(e.target.value))} placeholder="052-1234567" /></div>
                  <div className="form-group"><label>קוד אישי חדש</label>
                    <input type="password" value={form.pin} maxLength={4} onChange={e => set("pin",e.target.value)} placeholder="••••" /></div>
                  <div style={{ display:"flex", gap:"0.7rem" }}>
                    <button className="btn btn-primary" onClick={saveProfile}>שמור</button>
                    <button className="btn btn-secondary" onClick={() => setEditMode(false)}>ביטול</button>
                  </div>
                </>
              ) : (
                <div style={{ display:"flex", flexDirection:"column", gap:"0.7rem" }}>
                  {[["שם פרטי", reader?.firstName],["שם משפחה", reader?.lastName],["טלפון", reader?.phone]].map(([l,v]) => (
                    <div key={l}>
                      <div style={{ fontSize:"0.8rem", color:"#888" }}>{l}</div>
                      <div style={{ fontSize:"1.1rem", color:"var(--stamp)" }}>{v}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}
        {page === "catalog" && (
          <div>
            <div className="section-header"><h2 className="section-title">קטלוג הספרייה</h2></div>
            <div className="books-grid">
              {books.map(b => {
                const loaned = loans.some(l => l.bookId === b.id && !l.returned);
                return (
                  <div key={b.id} className="book-card">
                    <div className="book-cover">
                      {b.cover ? <img src={b.cover} alt={b.title} /> : "📖"}
                      <div className="book-cover-label">{loaned ? "LOANED" : "AVAILABLE"}</div>
                    </div>
                    <div className="book-info">
                      <div className="book-title">{b.title}</div>
                      <div className="book-author">{b.author}</div>
                      <span className={`book-badge ${loaned ? "badge-loaned" : "badge-available"}`}>
                        {loaned ? "מושאל" : "זמין"}
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}
